#!/usr/bin/env bash
# Global Claude Code PreToolUse hook (matcher: Edit|Write).
#
# Blocks edits/writes to sensitive paths that should never be modified
# directly by an LLM:
#   - secrets:           .env, .env.* (any depth)
#   - VCS internals:     .git/
#   - lockfiles:         uv.lock, poetry.lock, package-lock.json, Cargo.lock
#   - build/cache dirs:  .venv/, node_modules/, __pycache__/, target/
#   - data/results dirs: data/, cache/, results/  (CLAUDE.md: never commit these)
#
# Lockfiles should be regenerated by their package manager (`uv add`, etc.),
# not hand-edited. Data/cache/results dirs typically contain ignored or
# external-storage-bound artifacts.
#
# Override mechanism: set EDITS_TO_PROTECTED_PATHS_OK=1 when launching
# `claude` to disable this hook for that session.

set -uo pipefail

if [ "${EDITS_TO_PROTECTED_PATHS_OK:-}" = "1" ]; then
    exit 0
fi

PAYLOAD=$(cat)

FILE_PATH=$(printf '%s' "$PAYLOAD" | python3 -c '
import json, sys
try:
    d = json.load(sys.stdin)
    print(d.get("tool_input", {}).get("file_path", ""), end="")
except Exception:
    pass
' 2>/dev/null) || FILE_PATH=""

if [ -z "$FILE_PATH" ]; then
    exit 0
fi

# Normalize: ensure leading slash so substring match anchors to a path
# component boundary. Edit/Write tools require absolute paths in practice,
# but be defensive.
NORMALIZED="$FILE_PATH"
case "$NORMALIZED" in
    /*) ;;
    *)  NORMALIZED="/$NORMALIZED" ;;
esac

# Each pattern is matched as a substring of the (slash-prefixed) path.
# The leading slash anchors to a path-component boundary, so:
#   "/data/" matches "/foo/data/x" but NOT "/dataset/x" (no slash after "data").
PATTERNS=(
    "/.env"                  # .env, .env.local, .env.production, etc.
    "/.git/"
    "/uv.lock"
    "/poetry.lock"
    "/package-lock.json"
    "/Cargo.lock"
    "/.venv/"
    "/node_modules/"
    "/__pycache__/"
    "/target/"               # rust build output
    "/data/"
    "/cache/"
    "/results/"
)

for pattern in "${PATTERNS[@]}"; do
    case "$NORMALIZED" in
        *"$pattern"*)
            cat >&2 <<EOF
Blocked: '$FILE_PATH' matches protected pattern '$pattern'.

This hook (~/.claude/hooks/protect-paths.sh) blocks Edit/Write to:
  - secrets (.env*)
  - VCS internals (.git/)
  - lockfiles (uv.lock, poetry.lock, package-lock.json, Cargo.lock) —
    regenerate via the package manager instead
  - build/cache dirs (.venv/, node_modules/, __pycache__/, target/)
  - data/cache/results dirs (should not be committed)

If you genuinely need to modify this file:
  1. Ask the user to do it manually, or
  2. Have the user relaunch Claude with EDITS_TO_PROTECTED_PATHS_OK=1 set,
     or
  3. Edit ~/.claude/hooks/protect-paths.sh to remove the pattern.
EOF
            exit 2
            ;;
    esac
done

exit 0
